// Extrai campos do payload Evolution API
const body = $input.item.json.body ?? $input.item.json;
const data = body.data ?? body;

const remoteJid = data.key?.remoteJid ?? '';
const phone = remoteJid.replace('@s.whatsapp.net', '');
const fromMe = data.key?.fromMe ?? false;
const messageId = data.key?.id ?? '';
const messageType = data.messageType ?? '';

const textMessage =
  data.message?.conversation ||
  data.message?.extendedTextMessage?.text ||
  data.message?.imageMessage?.caption ||
  '';

const hasImage = !!(data.message?.imageMessage);
const hasAudio = !textMessage && !!(data.message?.audioMessage || data.message?.pttMessage);

// Detecta intenção de diagnóstico
const isDiagnosisIntent = /diag[nó]?[os]?t?i?c?o?|diag\s+piv[oô]|umidade\s+solo|solo\s+piv/i.test(textMessage);

// Extrai nome/número do pivô
const pivotMatch = textMessage.match(/piv[oô]?\s*([a-zA-Z0-9\s]+)/i);
const pivotHint = (pivotMatch?.[1] ?? '').trim().toUpperCase();

return [{
  json: {
    phone,
    fromMe,
    messageId,
    messageType,
    textMessage,
    msgUpper: textMessage.toUpperCase().trim(),
    hasImage,
    hasAudio,
    isDiagnosisIntent,
    pivotHint,
    rawData: data
  }
}];

parameters.output:
={{ (() => {
  const msg = $('Parse Message').item.json;
  const sessions = $('Buscar Sessão').item.json;
  const session = Array.isArray(sessions) ? sessions[0] : null;
  const expired = session && new Date(session.expires_at) < new Date();
  const active = session && !expired && session.current_flow === 'soil_diagnosis';

  if (!active && msg.isDiagnosisIntent) return 'diagnosis_start';
  if (active && session.flow_step === 'awaiting_behavior' && /^[1-5]$/.test(msg.msgUpper)) return 'handle_behavior';
  if (active && session.flow_step === 'awaiting_photo' && msg.hasImage) return 'handle_photo';
  if (active && session.flow_step === 'awaiting_photo' && /pular|sem foto/i.test(msg.textMessage)) return 'handle_skip';
  if (session && expired && session.current_flow === 'soil_diagnosis') return 'session_expired';
  return 'other';
})() }}

